use serde::{Serialize, Deserialize};

#[derive(Debug, Serialize, Deserialize)]
enum Command {
    Add(String),
    Remove(String),
}

struct History {
    commands: Vec<Command>,
}

impl History {
    fn execute(&mut self, cmd: Command) {
        self.commands.push(cmd);
    }

    fn undo_last(&mut self) {
        if let Some(last) = self.commands.pop() {
            match last {
                Command::Add(_) => println!("Undo Add"),
                Command::Remove(_) => println!("Undo Remove"),
            }
        }
    }
}

fn main() {
    let mut history = History { commands: vec![] };
    history.execute(Command::Add("hello".to_string()));
    history.undo_last();
}

